+import { mkdir, readdir, readFile, writeFile } from "node:fs/promises";
+import { basename, join } from "node:path";
+
+type MemoryCommand = "list" | "read" | "write" | "search";
+
+function stringArg(args: Record<string, unknown>, key: string): string | undefined {
+	const value = args[key];
+	return typeof value === "string" ? value : undefined;
+}
+
+function commandArg(value: unknown): MemoryCommand | undefined {
+	return value === "list" || value === "read" || value === "write" || value === "search"
+		? value
+		: undefined;
+}
+
+function validateFilename(filename: string): string {
+	if (!filename.trim()) throw new Error("filename must be non-empty");
+	if (filename !== basename(filename) || filename === "." || filename === "..") {
+		throw new Error("filename must be a simple basename (no path separators)");
+	}
+	if (filename.includes("\0")) throw new Error("filename must not contain NUL bytes");
+	return filename;
+}
+
+async function listDocuments(memoryDir: string): Promise<string> {
+	let entries: string[];
+	try {
+		entries = await readdir(memoryDir);
+	} catch {
+		return "No memory directory yet. Write a document to create it.";
+	}
+
+	const rows: string[] = [];
+	for (const name of entries.filter((entry) => entry.endsWith(".md")).sort()) {
+		const content = await readFile(join(memoryDir, name), "utf-8");
+		const title = content.split("\n")[0] ?? "";
+		rows.push(`${name.padEnd(30)} ${title}`);
+	}
+	return rows.length > 0 ? rows.join("\n") : "No memory documents found.";
+}
+
+async function readDocument(memoryDir: string, filename: string): Promise<string> {
+	const safeName = validateFilename(filename);
+	return readFile(join(memoryDir, safeName), "utf-8");
+}
+
+async function writeDocument(
+	memoryDir: string,
+	filename: string,
+	content: string,
+): Promise<string> {
+	const safeName = validateFilename(filename);
+	await mkdir(memoryDir, { recursive: true });
+	await writeFile(join(memoryDir, safeName), content, "utf-8");
+	return `Wrote ${safeName} (${content.length} bytes)`;
+}
+
+async function searchDocuments(memoryDir: string, keyword: string): Promise<string> {
+	if (!keyword) throw new Error("search keyword must be non-empty");
+	let entries: string[];
+	try {
+		entries = await readdir(memoryDir);
+	} catch {
+		return "No memory directory yet. Nothing to search.";
+	}
+
+	const sections: string[] = [];
+	for (const name of entries.filter((entry) => entry.endsWith(".md")).sort()) {
+		const content = await readFile(join(memoryDir, name), "utf-8");
+		const matches = content
+			.split("\n")
+			.map((line, index) => ({ line, number: index + 1 }))
+			.filter(({ line }) => line.includes(keyword));
+		if (matches.length === 0) continue;
+		sections.push(
+			[`=== ${name} ===`, ...matches.map(({ line, number }) => `${number}:${line}`)].join("\n"),
+		);
+	}
+
+	return sections.length > 0 ? sections.join("\n\n") : "No matches found.";
+}
+
+export default async function memoryCli(ctx) {
+	const command = commandArg(ctx.args.command);
+	if (!command) {
+		return {
+			output:
+				'Error: args must be JSON with command "list", "read", "write", or "search"',
+			success: false,
+			error: "missing or invalid command",
+		};
+	}
+
+	const projectDataDir = ctx.projectDataDir;
+	if (typeof projectDataDir !== "string" || !projectDataDir.trim()) {
+		return {
+			output: "Error: project data directory is unavailable for project-memory",
+			success: false,
+			error: "missing projectDataDir",
+		};
+	}
+
+	try {
+		const memoryDir = join(projectDataDir, "memory");
+		if (command === "list") {
+			return { output: await listDocuments(memoryDir), success: true };
+		}
+
+		if (command === "read") {
+			const filename = stringArg(ctx.args, "filename");
+			if (!filename) throw new Error("read requires filename");
+			return { output: await readDocument(memoryDir, filename), success: true };
+		}
+
+		if (command === "write") {
+			const filename = stringArg(ctx.args, "filename");
+			const content = stringArg(ctx.args, "content");
+			if (!filename) throw new Error("write requires filename");
+			if (content === undefined) throw new Error("write requires content");
+			return { output: await writeDocument(memoryDir, filename, content), success: true };
+		}
+
+		const keyword = stringArg(ctx.args, "keyword");
+		if (!keyword) throw new Error("search requires keyword");
+		return { output: await searchDocuments(memoryDir, keyword), success: true };
+	} catch (error) {
+		const message = error instanceof Error ? error.message : String(error);
+		return {
+			output: `Error: ${message}`,
+			success: false,
+			error: message,
+		};
+	}
+}

